// MinimockMemberUpdateInspect logs each unmet expectation
func (m *ClientMock) MinimockMemberUpdateInspect() {
	for _, e := range m.MemberUpdateMock.expectations {
		if mm_atomic.LoadUint64(&e.Counter) < 1 {
			m.t.Errorf("Expected call to ClientMock.MemberUpdate at\n%s with params: %#v", e.expectationOrigins.origin, *e.params)
		}
	}

	afterMemberUpdateCounter := mm_atomic.LoadUint64(&m.afterMemberUpdateCounter)
	// if default expectation was set then invocations count should be greater than zero
	if m.MemberUpdateMock.defaultExpectation != nil && afterMemberUpdateCounter < 1 {
		if m.MemberUpdateMock.defaultExpectation.params == nil {
			m.t.Errorf("Expected call to ClientMock.MemberUpdate at\n%s", m.MemberUpdateMock.defaultExpectation.returnOrigin)
		} else {
			m.t.Errorf("Expected call to ClientMock.MemberUpdate at\n%s with params: %#v", m.MemberUpdateMock.defaultExpectation.expectationOrigins.origin, *m.MemberUpdateMock.defaultExpectation.params)
		}
	}
	// if func was set then invocations count should be greater than zero
	if m.funcMemberUpdate != nil && afterMemberUpdateCounter < 1 {
		m.t.Errorf("Expected call to ClientMock.MemberUpdate at\n%s", m.funcMemberUpdateOrigin)
	}

	if !m.MemberUpdateMock.invocationsDone() && afterMemberUpdateCounter > 0 {
		m.t.Errorf("Expected %d calls to ClientMock.MemberUpdate at\n%s but found %d calls",
			mm_atomic.LoadUint64(&m.MemberUpdateMock.expectedInvocations), m.MemberUpdateMock.expectedInvocationsOrigin, afterMemberUpdateCounter)
	}
}

